package main.rice.test;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Objects;

/**
 * Represents a single test case consisting of one or more input arguments.
 */
public class TestCase {

    /** The list of arguments for this test case. */
    private final List<APyObj> args;

    /**
     * Constructor for a TestCase.
     *
     * @param args the list of input arguments
     */
    public TestCase(List<APyObj> args) {
        this.args = args;
    }

    /**
     * Returns the list of arguments for this test case.
     *
     * @return the arguments
     */
    public List<APyObj> getArgs() {
        return this.args;
    }

    /**
     * Compares this TestCase to another by value (argument equality).
     *
     * @param obj the object to compare against
     * @return true if the test cases have equal arguments
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof TestCase other)) {
            return false;
        }
        return this.args.equals(other.args);
    }

    /**
     * Returns a hash code based on the argument list.
     *
     * @return the hash code
     */
    @Override
    public int hashCode() {
        return Objects.hash(this.args);
    }

    /**
     * Returns a string representation of this test case.
     *
     * @return string representation
     */
    @Override
    public String toString() {
        return "TestCase" + this.args.toString();
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyListObj;
import java.util.*;

/**
 * A node that generates Python list values.
 * The exDomain and ranDomain specify the possible lengths.
 * The leftChild node generates the inner elements.
 *
 * @param <InnerType> the type of elements in the generated lists
 */
public class PyListNode<InnerType extends APyObj>
        extends AIterablePyNode<InnerType, PyListObj<InnerType>> {

    private static final Random random = new Random();

    /**
     * Constructor for a PyListNode.
     *
     * @param leftChild the node that generates inner elements
     */
    public PyListNode(APyNode<InnerType> leftChild) {
        super(leftChild);
    }

    /**
     * Generates all exhaustive list values. For each length in exDomain,
     * generates all lists of that length using elements from leftChild.genExVals()
     * (with repetition allowed).
     *
     * @return a set of all exhaustive PyListObj values
     */
    @Override
    public Set<PyListObj<InnerType>> genExVals() {
        Set<PyListObj<InnerType>> result = new HashSet<>();
        Set<InnerType> elements = leftChild.genExVals();

        for (Integer length : this.exDomain) {
            // Generate all lists of this length (with repetition)
            List<List<InnerType>> combos = genWithRepetition(new ArrayList<>(elements), length);
            for (List<InnerType> combo : combos) {
                result.add(new PyListObj<>(combo));
            }
        }
        return result;
    }

    /**
     * Generates a single random list. Picks a random length from ranDomain,
     * then for each position calls leftChild.genRandVal().
     *
     * @return a random PyListObj
     */
    @Override
    public PyListObj<InnerType> genRandVal() {
        int length = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        List<InnerType> elements = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            elements.add(leftChild.genRandVal());
        }
        return new PyListObj<>(elements);
    }

    /**
     * Generates all lists of the given length from elements, with repetition allowed.
     */
    static <E> List<List<E>> genWithRepetition(List<E> elements, int length) {
        List<List<E>> combos = new ArrayList<>();
        combos.add(new ArrayList<>());

        for (int i = 0; i < length; i++) {
            List<List<E>> newCombos = new ArrayList<>();
            for (List<E> combo : combos) {
                for (E elem : elements) {
                    List<E> newCombo = new ArrayList<>(combo);
                    newCombo.add(elem);
                    newCombos.add(newCombo);
                }
            }
            combos = newCombos;
        }
        return combos;
    }
}

package main.rice.node;

import main.rice.obj.PyCharObj;
import main.rice.obj.PyStringObj;
import java.util.*;

/**
 * A node that generates Python string values.
 * Takes a string of allowed characters in its constructor.
 * Strings allow repeated characters (like lists).
 */
public class PyStringNode extends APyNode<PyStringObj> {

    private static final Random random = new Random();

    /** The set of allowed characters for generating strings. */
    private final List<PyCharObj> chars;

    /**
     * Constructor for a PyStringNode.
     *
     * @param chars a string whose characters are the allowed character domain
     */
    public PyStringNode(String chars) {
        this.chars = new ArrayList<>();
        for (int i = 0; i < chars.length(); i++) {
            this.chars.add(new PyCharObj(chars.charAt(i)));
        }
    }

    /**
     * Returns null since PyStringNode has no left child.
     *
     * @return null
     */
    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Generates all exhaustive string values. For each length in exDomain,
     * generates all strings of that length using the character domain (with repetition).
     *
     * @return a set of all exhaustive PyStringObj values
     */
    @Override
    public Set<PyStringObj> genExVals() {
        Set<PyStringObj> result = new HashSet<>();
        for (Integer length : this.exDomain) {
            List<List<PyCharObj>> combos = PyListNode.genWithRepetition(this.chars, length);
            for (List<PyCharObj> combo : combos) {
                result.add(new PyStringObj(combo));
            }
        }
        return result;
    }

    /**
     * Generates a single random string. Picks a random length from ranDomain,
     * then picks random characters from the character domain.
     *
     * @return a random PyStringObj
     */
    @Override
    public PyStringObj genRandVal() {
        int length = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        List<PyCharObj> elements = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            elements.add(this.chars.get(random.nextInt(this.chars.size())));
        }
        return new PyStringObj(elements);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;

/**
 * Abstract base class for iterable Python node types (list, tuple, set).
 * Has a left child that generates the inner elements.
 *
 * @param <InnerType> the type of objects generated by the left child
 * @param <T>         the type of iterable object this node generates
 */
public abstract class AIterablePyNode<InnerType extends APyObj, T extends APyObj>
        extends APyNode<T> {

    /** The child node that generates the inner elements. */
    protected APyNode<InnerType> leftChild;

    /**
     * Constructor for an AIterablePyNode.
     *
     * @param leftChild the node that generates inner elements
     */
    public AIterablePyNode(APyNode<InnerType> leftChild) {
        this.leftChild = leftChild;
    }

    /**
     * Returns the left child node.
     *
     * @return the left child node
     */
    @Override
    public APyNode<?> getLeftChild() {
        return this.leftChild;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyTupleObj;
import java.util.*;

/**
 * A node that generates Python tuple values.
 * Tuples allow duplicates and maintain order (same as lists in terms of generation).
 *
 * @param <InnerType> the type of elements in the generated tuples
 */
public class PyTupleNode<InnerType extends APyObj>
        extends AIterablePyNode<InnerType, PyTupleObj<InnerType>> {

    private static final Random random = new Random();

    /**
     * Constructor for a PyTupleNode.
     *
     * @param leftChild the node that generates inner elements
     */
    public PyTupleNode(APyNode<InnerType> leftChild) {
        super(leftChild);
    }

    /**
     * Generates all exhaustive tuple values. For each length in exDomain,
     * generates all tuples of that length using elements from leftChild.genExVals()
     * (with repetition allowed).
     *
     * @return a set of all exhaustive PyTupleObj values
     */
    @Override
    public Set<PyTupleObj<InnerType>> genExVals() {
        Set<PyTupleObj<InnerType>> result = new HashSet<>();
        Set<InnerType> elements = leftChild.genExVals();

        for (Integer length : this.exDomain) {
            List<List<InnerType>> combos = PyListNode.genWithRepetition(new ArrayList<>(elements), length);
            for (List<InnerType> combo : combos) {
                result.add(new PyTupleObj<>(combo));
            }
        }
        return result;
    }

    /**
     * Generates a single random tuple. Picks a random length from ranDomain,
     * then for each position calls leftChild.genRandVal().
     *
     * @return a random PyTupleObj
     */
    @Override
    public PyTupleObj<InnerType> genRandVal() {
        int length = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        List<InnerType> elements = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            elements.add(leftChild.genRandVal());
        }
        return new PyTupleObj<>(elements);
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;
import java.util.*;

/**
 * A node that generates Python dict values.
 * Has a left child (key generator) and right child (value generator).
 * Keys must be unique; values can repeat.
 *
 * @param <KeyType> the type of keys
 * @param <ValType> the type of values
 */
public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
        extends APyNode<PyDictObj<KeyType, ValType>> {

    private static final Random random = new Random();

    /** The child node that generates keys. */
    protected APyNode<KeyType> leftChild;

    /** The child node that generates values. */
    protected APyNode<ValType> rightChild;

    /**
     * Constructor for a PyDictNode.
     *
     * @param keyNode the node that generates keys
     * @param valNode the node that generates values
     */
    public PyDictNode(APyNode<KeyType> keyNode, APyNode<ValType> valNode) {
        this.leftChild = keyNode;
        this.rightChild = valNode;
    }

    /**
     * Returns the left child (key generator) node.
     *
     * @return the key node
     */
    @Override
    public APyNode<?> getLeftChild() {
        return this.leftChild;
    }

    /**
     * Returns the right child (value generator) node.
     *
     * @return the value node
     */
    @Override
    public APyNode<?> getRightChild() {
        return this.rightChild;
    }

    /**
     * Generates all exhaustive dict values. For each length in exDomain,
     * generates all C(|keys|, k) key combinations, and for each, all value
     * assignments (|vals|^k combinations).
     *
     * @return a set of all exhaustive PyDictObj values
     */
    @Override
    public Set<PyDictObj<KeyType, ValType>> genExVals() {
        Set<PyDictObj<KeyType, ValType>> result = new HashSet<>();
        List<KeyType> keyElems = new ArrayList<>(leftChild.genExVals());
        List<ValType> valElems = new ArrayList<>(rightChild.genExVals());

        for (Integer length : this.exDomain) {
            // Generate all k-combinations of keys (no duplicates)
            List<List<KeyType>> keyCombos = PySetNode.genCombinations(keyElems, length);

            for (List<KeyType> keyCombo : keyCombos) {
                // For this key combination, generate all value assignments
                List<List<ValType>> valAssignments =
                        PyListNode.genWithRepetition(valElems, length);

                for (List<ValType> valAssignment : valAssignments) {
                    Map<KeyType, ValType> map = new LinkedHashMap<>();
                    for (int i = 0; i < keyCombo.size(); i++) {
                        map.put(keyCombo.get(i), valAssignment.get(i));
                    }
                    result.add(new PyDictObj<>(map));
                }
            }
        }
        return result;
    }

    /**
     * Generates a single random dict. Picks a random size from ranDomain,
     * then picks distinct keys via leftChild.genRandVal() and values via
     * rightChild.genRandVal().
     *
     * @return a random PyDictObj
     */
    @Override
    public PyDictObj<KeyType, ValType> genRandVal() {
        int size = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        Map<KeyType, ValType> map = new LinkedHashMap<>();

        // Collect distinct keys
        Set<KeyType> keys = new LinkedHashSet<>();
        while (keys.size() < size) {
            keys.add(leftChild.genRandVal());
        }

        // Assign random value to each key
        for (KeyType key : keys) {
            map.put(key, rightChild.genRandVal());
        }
        return new PyDictObj<>(map);
    }
}

package main.rice.node;

import main.rice.obj.PyIntObj;
import java.util.HashSet;
import java.util.Random;
import java.util.Set;

/**
 * A node that generates Python int values.
 * The exDomain and ranDomain contain the actual integer values (not lengths).
 */
public class PyIntNode extends APyNode<PyIntObj> {

    private static final Random random = new Random();

    /**
     * Generates all exhaustive integer values from the exDomain.
     *
     * @return a set of all PyIntObj values in the exhaustive domain
     */
    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> result = new HashSet<>();
        for (Integer val : this.exDomain) {
            result.add(new PyIntObj(val));
        }
        return result;
    }

    /**
     * Generates a single random integer value from the ranDomain.
     *
     * @return a random PyIntObj from the random domain
     */
    @Override
    public PyIntObj genRandVal() {
        int idx = random.nextInt(this.ranDomain.size());
        return new PyIntObj(this.ranDomain.get(idx));
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PySetObj;
import java.util.*;

/**
 * A node that generates Python set values.
 * Sets don't allow duplicates, so exhaustive generation uses combinations
 * (not permutations with repetition).
 *
 * @param <InnerType> the type of elements in the generated sets
 */
public class PySetNode<InnerType extends APyObj>
        extends AIterablePyNode<InnerType, PySetObj<InnerType>> {

    private static final Random random = new Random();

    /**
     * Constructor for a PySetNode.
     *
     * @param leftChild the node that generates inner elements
     */
    public PySetNode(APyNode<InnerType> leftChild) {
        super(leftChild);
    }

    /**
     * Generates all exhaustive set values. For each length in exDomain,
     * generates all k-element subsets of leftChild.genExVals() (no duplicates).
     *
     * @return a set of all exhaustive PySetObj values
     */
    @Override
    public Set<PySetObj<InnerType>> genExVals() {
        Set<PySetObj<InnerType>> result = new HashSet<>();
        List<InnerType> elements = new ArrayList<>(leftChild.genExVals());

        for (Integer length : this.exDomain) {
            List<List<InnerType>> combos = genCombinations(elements, length);
            for (List<InnerType> combo : combos) {
                result.add(new PySetObj<>(new HashSet<>(combo)));
            }
        }
        return result;
    }

    /**
     * Generates a single random set. Picks a random length from ranDomain,
     * then picks that many distinct elements using leftChild.genRandVal().
     *
     * @return a random PySetObj
     */
    @Override
    public PySetObj<InnerType> genRandVal() {
        int length = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
        Set<InnerType> elements = new HashSet<>();
        while (elements.size() < length) {
            elements.add(leftChild.genRandVal());
        }
        return new PySetObj<>(elements);
    }

    /**
     * Generates all k-element combinations (without repetition) from the given list.
     */
    static <E> List<List<E>> genCombinations(List<E> elements, int k) {
        List<List<E>> result = new ArrayList<>();
        if (k == 0) {
            result.add(new ArrayList<>());
            return result;
        }
        for (int i = 0; i <= elements.size() - k; i++) {
            List<List<E>> subCombos = genCombinations(
                    elements.subList(i + 1, elements.size()), k - 1);
            for (List<E> combo : subCombos) {
                List<E> newCombo = new ArrayList<>();
                newCombo.add(elements.get(i));
                newCombo.addAll(combo);
                result.add(newCombo);
            }
        }
        return result;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * Abstract base class for all Python node types.
 * A node represents a domain of possible Python values and can generate them.
 *
 * @param <T> the type of Python object this node generates
 */
public abstract class APyNode<T extends APyObj> {

    /** The exhaustive domain (lengths for iterables, values for scalars). */
    protected List<Integer> exDomain;

    /** The random domain (lengths for iterables, values for scalars). */
    protected List<Integer> ranDomain;

    /**
     * Sets the exhaustive domain.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Returns the exhaustive domain.
     *
     * @return the exhaustive domain
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the random domain.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Returns the random domain.
     *
     * @return the random domain
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Returns the left child node, or null if none.
     *
     * @return the left child node
     */
    public APyNode<?> getLeftChild() {
        return null;
    }

    /**
     * Returns the right child node, or null if none.
     *
     * @return the right child node
     */
    public APyNode<?> getRightChild() {
        return null;
    }

    /**
     * Generates all exhaustive values based on the exhaustive domain.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<T> genExVals();

    /**
     * Generates a single random value based on the random domain.
     *
     * @return a random value
     */
    public abstract T genRandVal();
}

package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;
import java.util.*;

/**
 * Generates a base set of test cases from a list of argument node specifications.
 * Supports exhaustive generation (Cartesian product) and random generation.
 */
public class BaseSetGenerator {

    /** The nodes specifying the argument domains. */
    private final List<APyNode<?>> nodes;

    /** The number of random tests to generate. */
    private final int numRand;

    /** The cached set of exhaustive test cases (populated by genExTests()). */
    private Set<TestCase> exTests;

    /**
     * Constructor for a BaseSetGenerator.
     *
     * @param nodes   the argument nodes
     * @param numRand the number of random tests to generate
     */
    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = nodes;
        this.numRand = numRand;
    }

    /**
     * Generates all exhaustive test cases by computing the Cartesian product
     * of each node's exhaustive values.
     *
     * @return a set of all exhaustive test cases
     */
    public Set<TestCase> genExTests() {
        exTests = new HashSet<>();

        // Build Cartesian product iteratively
        List<List<APyObj>> combos = new ArrayList<>();
        combos.add(new ArrayList<>());

        for (APyNode<?> node : nodes) {
            List<APyObj> vals = new ArrayList<>(node.genExVals());
            List<List<APyObj>> newCombos = new ArrayList<>();
            for (List<APyObj> combo : combos) {
                for (APyObj val : vals) {
                    List<APyObj> newCombo = new ArrayList<>(combo);
                    newCombo.add(val);
                    newCombos.add(newCombo);
                }
            }
            combos = newCombos;
        }

        for (List<APyObj> combo : combos) {
            exTests.add(new TestCase(combo));
        }
        return exTests;
    }

    /**
     * Generates random test cases, avoiding any already in the exhaustive set.
     * Requires genExTests() to have been called first.
     *
     * @return a set of random test cases not overlapping with the exhaustive set
     */
    public Set<TestCase> genRandTests() {
        Set<TestCase> randTests = new HashSet<>();
        if (numRand == 0) {
            return randTests;
        }

        // Use empty set if exTests hasn't been populated yet
        Set<TestCase> existing = (exTests != null) ? exTests : new HashSet<>();
        int maxAttempts = numRand * 1000;
        int attempts = 0;

        while (randTests.size() < numRand && attempts < maxAttempts) {
            List<APyObj> args = new ArrayList<>();
            for (APyNode<?> node : nodes) {
                args.add(node.genRandVal());
            }
            TestCase tc = new TestCase(args);
            if (!existing.contains(tc) && !randTests.contains(tc)) {
                randTests.add(tc);
            }
            attempts++;
        }
        return randTests;
    }

    /**
     * Generates the full base set: all exhaustive tests followed by random tests.
     * Exhaustive tests come first; random tests do not duplicate exhaustive.
     *
     * @return a list of test cases (exhaustive first, then random)
     */
    public List<TestCase> genBaseSet() {
        Set<TestCase> ex = genExTests();
        Set<TestCase> rand = genRandTests();
        List<TestCase> result = new ArrayList<>(ex);
        result.addAll(rand);
        return result;
    }
}

