+package main.rice.node;
+
+import main.rice.obj.APyObj;
+import main.rice.obj.PyListObj;
+import java.util.*;
+
+/**
+ * A node that generates Python list values.
+ * The exDomain and ranDomain specify the possible lengths.
+ * The leftChild node generates the inner elements.
+ *
+ * @param <InnerType> the type of elements in the generated lists
+ */
+public class PyListNode<InnerType extends APyObj>
+        extends AIterablePyNode<InnerType, PyListObj<InnerType>> {
+
+    private static final Random random = new Random();
+
+    /**
+     * Constructor for a PyListNode.
+     *
+     * @param leftChild the node that generates inner elements
+     */
+    public PyListNode(APyNode<InnerType> leftChild) {
+        super(leftChild);
+    }
+
+    /**
+     * Generates all exhaustive list values. For each length in exDomain,
+     * generates all lists of that length using elements from leftChild.genExVals()
+     * (with repetition allowed).
+     *
+     * @return a set of all exhaustive PyListObj values
+     */
+    @Override
+    public Set<PyListObj<InnerType>> genExVals() {
+        Set<PyListObj<InnerType>> result = new HashSet<>();
+        Set<InnerType> elements = leftChild.genExVals();
+
+        for (Integer length : this.exDomain) {
+            // Generate all lists of this length (with repetition)
+            List<List<InnerType>> combos = genWithRepetition(new ArrayList<>(elements), length);
+            for (List<InnerType> combo : combos) {
+                result.add(new PyListObj<>(combo));
+            }
+        }
+        return result;
+    }
+
+    /**
+     * Generates a single random list. Picks a random length from ranDomain,
+     * then for each position calls leftChild.genRandVal().
+     *
+     * @return a random PyListObj
+     */
+    @Override
+    public PyListObj<InnerType> genRandVal() {
+        int length = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
+        List<InnerType> elements = new ArrayList<>();
+        for (int i = 0; i < length; i++) {
+            elements.add(leftChild.genRandVal());
+        }
+        return new PyListObj<>(elements);
+    }
+
+    /**
+     * Generates all lists of the given length from elements, with repetition allowed.
+     */
+    static <E> List<List<E>> genWithRepetition(List<E> elements, int length) {
+        List<List<E>> combos = new ArrayList<>();
+        combos.add(new ArrayList<>());
+
+        for (int i = 0; i < length; i++) {
+            List<List<E>> newCombos = new ArrayList<>();
+            for (List<E> combo : combos) {
+                for (E elem : elements) {
+                    List<E> newCombo = new ArrayList<>(combo);
+                    newCombo.add(elem);
+                    newCombos.add(newCombo);
+                }
+            }
+            combos = newCombos;
+        }
+        return combos;
+    }
+}
