+package main.rice.node;
+
+import main.rice.obj.APyObj;
+import main.rice.obj.PySetObj;
+import java.util.*;
+
+/**
+ * A node that generates Python set values.
+ * Sets don't allow duplicates, so exhaustive generation uses combinations
+ * (not permutations with repetition).
+ *
+ * @param <InnerType> the type of elements in the generated sets
+ */
+public class PySetNode<InnerType extends APyObj>
+        extends AIterablePyNode<InnerType, PySetObj<InnerType>> {
+
+    private static final Random random = new Random();
+
+    /**
+     * Constructor for a PySetNode.
+     *
+     * @param leftChild the node that generates inner elements
+     */
+    public PySetNode(APyNode<InnerType> leftChild) {
+        super(leftChild);
+    }
+
+    /**
+     * Generates all exhaustive set values. For each length in exDomain,
+     * generates all k-element subsets of leftChild.genExVals() (no duplicates).
+     *
+     * @return a set of all exhaustive PySetObj values
+     */
+    @Override
+    public Set<PySetObj<InnerType>> genExVals() {
+        Set<PySetObj<InnerType>> result = new HashSet<>();
+        List<InnerType> elements = new ArrayList<>(leftChild.genExVals());
+
+        for (Integer length : this.exDomain) {
+            List<List<InnerType>> combos = genCombinations(elements, length);
+            for (List<InnerType> combo : combos) {
+                result.add(new PySetObj<>(new HashSet<>(combo)));
+            }
+        }
+        return result;
+    }
+
+    /**
+     * Generates a single random set. Picks a random length from ranDomain,
+     * then picks that many distinct elements using leftChild.genRandVal().
+     *
+     * @return a random PySetObj
+     */
+    @Override
+    public PySetObj<InnerType> genRandVal() {
+        int length = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
+        Set<InnerType> elements = new HashSet<>();
+        while (elements.size() < length) {
+            elements.add(leftChild.genRandVal());
+        }
+        return new PySetObj<>(elements);
+    }
+
+    /**
+     * Generates all k-element combinations (without repetition) from the given list.
+     */
+    static <E> List<List<E>> genCombinations(List<E> elements, int k) {
+        List<List<E>> result = new ArrayList<>();
+        if (k == 0) {
+            result.add(new ArrayList<>());
+            return result;
+        }
+        for (int i = 0; i <= elements.size() - k; i++) {
+            List<List<E>> subCombos = genCombinations(
+                    elements.subList(i + 1, elements.size()), k - 1);
+            for (List<E> combo : subCombos) {
+                List<E> newCombo = new ArrayList<>();
+                newCombo.add(elements.get(i));
+                newCombo.addAll(combo);
+                result.add(newCombo);
+            }
+        }
+        return result;
+    }
+}
