+package main.rice.node;
+
+import main.rice.obj.PyCharObj;
+import main.rice.obj.PyStringObj;
+import java.util.*;
+
+/**
+ * A node that generates Python string values.
+ * Takes a string of allowed characters in its constructor.
+ * Strings allow repeated characters (like lists).
+ */
+public class PyStringNode extends APyNode<PyStringObj> {
+
+    private static final Random random = new Random();
+
+    /** The set of allowed characters for generating strings. */
+    private final List<PyCharObj> chars;
+
+    /**
+     * Constructor for a PyStringNode.
+     *
+     * @param chars a string whose characters are the allowed character domain
+     */
+    public PyStringNode(String chars) {
+        this.chars = new ArrayList<>();
+        for (int i = 0; i < chars.length(); i++) {
+            this.chars.add(new PyCharObj(chars.charAt(i)));
+        }
+    }
+
+    /**
+     * Returns null since PyStringNode has no left child.
+     *
+     * @return null
+     */
+    @Override
+    public APyNode<?> getLeftChild() {
+        return null;
+    }
+
+    /**
+     * Generates all exhaustive string values. For each length in exDomain,
+     * generates all strings of that length using the character domain (with repetition).
+     *
+     * @return a set of all exhaustive PyStringObj values
+     */
+    @Override
+    public Set<PyStringObj> genExVals() {
+        Set<PyStringObj> result = new HashSet<>();
+        for (Integer length : this.exDomain) {
+            List<List<PyCharObj>> combos = PyListNode.genWithRepetition(this.chars, length);
+            for (List<PyCharObj> combo : combos) {
+                result.add(new PyStringObj(combo));
+            }
+        }
+        return result;
+    }
+
+    /**
+     * Generates a single random string. Picks a random length from ranDomain,
+     * then picks random characters from the character domain.
+     *
+     * @return a random PyStringObj
+     */
+    @Override
+    public PyStringObj genRandVal() {
+        int length = this.ranDomain.get(random.nextInt(this.ranDomain.size()));
+        List<PyCharObj> elements = new ArrayList<>();
+        for (int i = 0; i < length; i++) {
+            elements.add(this.chars.get(random.nextInt(this.chars.size())));
+        }
+        return new PyStringObj(elements);
+    }
+}
